mapper.insert:
INSERT INTO tb_mandalart_node ( cell_id, mandalart_id, user_id, reg_date, lvl, cell_row, cell_col, mandalart_content, upd_id, upd_dt, reg_id, reg_dt ) VALUES
( #{item.cellId}, #{item.mandalartId}, #{item.userId}, #{item.regDate}::date, #{item.lvl}, #{item.cellRow}, #{item.cellCol}, #{item.mandalartContent}, #{item.userId}, now(), #{item.userId}, now() )
ON CONFLICT (mandalart_id, cell_id) DO UPDATE SET mandalart_content = EXCLUDED.mandalart_content, upd_id = EXCLUDED.upd_id, upd_dt = now() ;

mapper.update:
UPDATE tb_mandalart_node SET
    mandalart_content = #{mandalartContent},
    upd_id            = #{userId},
    upd_dt            = now()
WHERE mandalart_id = #{mandalartId}
AND   cell_id = #{cellId}
;

DELETE FROM tb_mandalart_node
WHERE mandalart_id = #{mandalartId}
AND   cell_id = #{cellId}
;

